// SDK research findings
// python-smartdevice v2.3.1 supports:
//   - on/off toggle
//   - mode switching (eco/boost/schedule)
//   - device info query
// NOT supported:
//   - target temperature setting
//   - timer duration control
//   - custom schedule creation
// Conclusion: need to find lower-level API

// Discovered API details from SDK source inspection:
// Endpoint: https://api.smartdevice.cloud/graphql
// Auth: Bearer token from OAuth2 flow
// Key mutations found in source:
//   setDeviceProperty(deviceId, property, value)
//   batchSetProperties(deviceId, properties[])
// Key queries:
//   device(id) { properties { key value } }
//   devices { id name type online }
//
// Token refresh: POST /auth/refresh with refresh_token

async function setWaterHeaterTemp(token, deviceId, targetTemp) {
  const endpoint = "https://api.smartdevice.cloud/graphql";
  const mutation = `mutation {
    setDeviceProperty(
      deviceId: "${deviceId}",
      property: "target_temperature",
      value: ${targetTemp}
    ) { success message }
  }`;
  const res = await fetch(endpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${token}`,
    },
    body: JSON.stringify({ query: mutation }),
  });
  const data = await res.json();
  if (!data?.data?.setDeviceProperty?.success) {
    throw new Error(data?.errors?.[0]?.message || "mutation failed");
  }
  // Verify by querying current state
  const verify = await fetch(endpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${token}`,
    },
    body: JSON.stringify({
      query: `{ device(id: "${deviceId}") {
        properties { key value }
      }}`,
    }),
  });
  const state = await verify.json();
  const currentTemp = state?.data?.device?.properties
    ?.find(p => p.key === "target_temperature")?.value;
  return { success: true, set: targetTemp, verified: currentTemp };
}

